AND type = 'STORE' AND brand_code = #{brandCode}
AND (name LIKE CONCAT('%', #{keyword}, '%') OR store_code LIKE CONCAT('%', #{keyword}, '%'))
AND status = #{status}
ORDER BY CASE type WHEN 'SYSTEM' THEN 1 WHEN 'HQ' THEN 2 WHEN 'STORE' THEN 3 ELSE 4 END ASC, brand_code ASC, store_code ASC LIMIT #{limit} OFFSET #{offset}

